import socket
import json
from typing import Dict, List

# Configuration
BIND_ADDRESS = '0.0.0.0'
BIND_PORT = 12345
MAX_RESPONSE_SIZE = 1024 * 1024  # 1MB

class GameServer:
    def __init__(self):
        self.players: Dict[str, str] = {}  # player name -> player ID
        self.game_state: Dict[str, any] = {}  # game state data

    def handle_status_query(self, sock: socket.socket) -> None:
        try:
            data, _ = sock.recvfrom(MAX_RESPONSE_SIZE)
            if not data:
                return

            query_data = json.loads(data.decode('utf-8'))
            if 'player_list' in query_data and 'game_state' in query_data:
                player_list = self.players
                game_state = self.game_state
            else:
                player_list = {}
                game_state = {}

            response = {
                'status': 'ok',
                'player_list': player_list,
                'game_state': game_state
            }
            sock.sendto(json.dumps(response).encode('utf-8'), ('127.0.0.1', 12345))
        except json.JSONDecodeError:
            pass

    def start(self) -> None:
        server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        server_socket.bind((BIND_ADDRESS, BIND_PORT))

        while True:
            self.handle_status_query(server_socket)

if __name__ == '__main__':
    game_server = GameServer()
    game_server.start()